import './App.css';
import React, { useState } from "react";

function App() {

  const [count, setCount] = useState(0);

  return (
    <div style={{ textAlign: "center", marginTop: "50px" }}>

      <h1>React Hook Example</h1>

      <h2>Count: {count}</h2>

      <button onClick={() => setCount(count + 1)}>
        Increase
      </button>
<button onClick={() => setCount(count - 1)}>
        Increase
      </button>
    </div>
  );
}

export default App;
